interface NoteTab {
  id: string;
  name: string;
  content: string;
}

interface NotesState {
  tabs: NoteTab[];
  activeIdx: number;
}

const NOTES_KEY = "dudidesk_notes";
const MAX_TABS = 7;

function loadNotes(): NotesState {
  try {
    const raw = localStorage.getItem(NOTES_KEY);
    if (raw) return JSON.parse(raw) as NotesState;
  } catch { /* */ }
  return { tabs: [{ id: "1", name: "NOTE 1", content: "" }], activeIdx: 0 };
}

function saveNotes(state: NotesState): void {
  localStorage.setItem(NOTES_KEY, JSON.stringify(state));
}

let undoStack: { tab: NoteTab; index: number } | null = null;

function renderNotesTabs(state: NotesState, textarea: HTMLTextAreaElement): void {
  const bar = document.getElementById("notesTabsBar");
  if (!bar) return;
  bar.innerHTML = "";

  let dragIdx = -1;

  bar.onpointerup = () => {
    dragIdx = -1;
    bar.querySelectorAll(".dragging").forEach(t => t.classList.remove("dragging"));
  };

  state.tabs.forEach((tab, idx) => {
    const el = document.createElement("div");
    el.className = "note-tab" + (idx === state.activeIdx ? " active" : "");

    const label = document.createElement("span");
    label.textContent = tab.name;

    el.addEventListener("click", () => {
      state.activeIdx = idx;
      saveNotes(state);
      textarea.value = state.tabs[idx].content;
      renderNotesTabs(state, textarea);
    });

    el.addEventListener("dblclick", e => {
      e.stopPropagation();
      const inp = document.createElement("input");
      inp.className = "note-tab-rename";
      inp.value = tab.name;
      inp.maxLength = 12;
      bar.replaceChild(inp, el);
      inp.focus();
      inp.select();
      const finish = () => {
        state.tabs[idx].name = inp.value.trim() || tab.name;
        saveNotes(state);
        renderNotesTabs(state, textarea);
      };
      inp.addEventListener("blur", finish);
      inp.addEventListener("keydown", k => { if (k.key === "Enter") inp.blur(); });
    });

    el.addEventListener("pointerdown", e => {
      if ((e.target as HTMLElement).closest(".note-tab-del")) return;
      dragIdx = idx;
      el.classList.add("dragging");
    });

    el.addEventListener("pointerup", () => {
      if (dragIdx >= 0 && dragIdx !== idx) {
        const tmp = state.tabs[dragIdx];
        state.tabs[dragIdx] = state.tabs[idx];
        state.tabs[idx] = tmp;
        if (state.activeIdx === dragIdx) state.activeIdx = idx;
        else if (state.activeIdx === idx) state.activeIdx = dragIdx;
        saveNotes(state);
        textarea.value = state.tabs[state.activeIdx].content;
        renderNotesTabs(state, textarea);
      }
      dragIdx = -1;
    });

    el.appendChild(label);

    if (state.tabs.length > 1) {
      const del = document.createElement("button");
      del.className = "note-tab-del";
      del.textContent = "×";
      del.addEventListener("click", e => {
        e.stopPropagation();
        undoStack = { tab: { ...state.tabs[idx] }, index: idx };
        state.tabs.splice(idx, 1);
        state.activeIdx = Math.min(state.activeIdx, state.tabs.length - 1);
        saveNotes(state);
        textarea.value = state.tabs[state.activeIdx].content;
        renderNotesTabs(state, textarea);
      });
      el.appendChild(del);
    }

    bar.appendChild(el);
  });

  if (state.tabs.length < MAX_TABS) {
    const addBtn = document.createElement("button");
    addBtn.className = "note-tab-add";
    addBtn.textContent = "+";
    addBtn.addEventListener("click", () => {
      const n = state.tabs.length + 1;
      state.tabs.push({ id: Date.now().toString(), name: `NOTE ${n}`, content: "" });
      state.activeIdx = state.tabs.length - 1;
      saveNotes(state);
      textarea.value = "";
      renderNotesTabs(state, textarea);
      textarea.focus();
    });
    bar.appendChild(addBtn);
  }

  if (undoStack) {
    const undoBtn = document.createElement("button");
    undoBtn.className = "note-tab-undo";
    undoBtn.textContent = "↩";
    undoBtn.title = "UNDO";
    undoBtn.addEventListener("click", () => {
      if (!undoStack) return;
      const insertAt = Math.min(undoStack.index, state.tabs.length);
      state.tabs.splice(insertAt, 0, undoStack.tab);
      state.activeIdx = insertAt;
      saveNotes(state);
      textarea.value = undoStack.tab.content;
      undoStack = null;
      renderNotesTabs(state, textarea);
    });
    bar.appendChild(undoBtn);
  }
}

export function initNotes(): void {
  const btn = document.getElementById("notesBtn");
  const panel = document.getElementById("notesPanel");
  const textarea = document.getElementById("notesTextarea") as HTMLTextAreaElement | null;
  if (!btn || !panel || !textarea) return;

  panel.addEventListener("click", e => e.stopPropagation());

  const notesHeader = document.createElement("div");
  notesHeader.className = "bw-panel-header";
  notesHeader.textContent = "// NOTES";
  panel.prepend(notesHeader);

  // reuse resize logic from todo module via shared helper isn't imported — inline it
  {
    const PANEL_SIZES_N = ["bw-sz-s", "bw-sz-m", "bw-sz-l"] as const;
    let szIdx = 1;
    panel.classList.add(PANEL_SIZES_N[szIdx]);

    const wrap = document.createElement("div");
    wrap.className = "bw-resize-btns";
    const minus = document.createElement("button");
    minus.className = "bw-resize-btn";
    minus.textContent = "−";
    (minus as HTMLButtonElement).disabled = true;
    const plus = document.createElement("button");
    plus.className = "bw-resize-btn";
    plus.textContent = "+";

    const apply = (delta: number): void => {
      panel.classList.remove(PANEL_SIZES_N[szIdx]);
      szIdx = Math.max(0, Math.min(PANEL_SIZES_N.length - 1, szIdx + delta));
      panel.classList.add(PANEL_SIZES_N[szIdx]);
      (minus as HTMLButtonElement).disabled = szIdx === 0;
      (plus as HTMLButtonElement).disabled = szIdx === PANEL_SIZES_N.length - 1;
    };
    minus.addEventListener("click", e => { e.stopPropagation(); apply(-1); });
    plus.addEventListener("click", e => { e.stopPropagation(); apply(1); });
    wrap.appendChild(minus);
    wrap.appendChild(plus);
    notesHeader.appendChild(wrap);
  }

  let state = loadNotes();

  btn.addEventListener("click", e => {
    e.stopPropagation();
    const opening = !panel.classList.contains("open");
    document.getElementById("todoPanel")?.classList.remove("open");
    panel.classList.toggle("open", opening);
    if (opening) {
      state = loadNotes();
      textarea.value = state.tabs[state.activeIdx]?.content ?? "";
      renderNotesTabs(state, textarea);
      textarea.focus();
    }
  });

  textarea.addEventListener("input", () => {
    const tab = state.tabs[state.activeIdx];
    if (tab) { tab.content = textarea.value; saveNotes(state); }
  });

  document.addEventListener("click", e => {
    if (!panel.contains(e.target as Node) && e.target !== btn)
      panel.classList.remove("open");
  });
}
